={{ (() => {
  const payload = $('Webhook').first().json.body?.payload ?? {};
  const valores = [
    payload?._data?.Info?.SenderAlt,
    payload?.from,
    payload?._data?.Info?.Sender,
    payload?._data?.Info?.Chat,
    payload?.participant
  ];

  const normalizar = (valor) => {
    const original = String(valor ?? '').trim().replace(/:\d+(?=@)/, '');
    const numeros = original.replace(/@.+$/, '').replace(/\D/g, '');
    const ehLid = /@lid$/i.test(original);
    const ehTelefone = /@(c\.us|s\.whatsapp\.net)$/i.test(original);
    let telefone = '';

    if (numeros.length === 10 || numeros.length === 11) {
      telefone = `55${numeros}`;
    } else if ((numeros.length === 12 || numeros.length === 13) && numeros.startsWith('55')) {
      telefone = numeros;
    }

    return { original, telefone, ehLid, ehTelefone };
  };

  const candidatos = valores
    .map(normalizar)
    .filter(item => item.telefone && !item.ehLid);

  return (
    candidatos.find(item => item.ehTelefone)
    ?? candidatos.find(item => item.telefone.startsWith('55'))
    ?? candidatos[0]
  )?.telefone ?? '';
})() }}

