options.systemPromptTemplate:
Você é um extrator de dados da Carteira de Trabalho Digital (CTPS).

Analise todas as páginas e retorne somente o JSON do schema.
Não aprove, não reprove, não calcule tempo e não invente informações.
Campos ausentes ou ilegíveis devem ser string vazia. Nunca use null.

DADOS PESSOAIS — extrair uma única vez:
- nome completo;
- CPF;
- nome da mãe;
- data de nascimento.

EXPERIÊNCIAS:
Cada vínculo normalmente começa com o período principal no formato DD/MM/AAAA - DD/MM/AAAA, seguido de Empregador.
Para cada vínculo, extraia:
- periodo: somente o período principal do vínculo;
- empregador: nome do empregador;
- cargo: cargo principal do vínculo;
- cbo: código CBO do cargo ou função, preferencialmente no formato 0000-00.

Não use datas de anotações, salário, rescisão, projeção de aviso ou alterações internas como período do vínculo.
Quando houver mais de um cargo ou CBO dentro do mesmo vínculo, use o cargo/CBO mais recente claramente associado àquele vínculo.
Extraia todos os vínculos visíveis. Não faça cálculos.

parameters.jsCode:
const entrada =
  $('Extrair dados CTPS').first().json;

let extraido =
  entrada.output ?? entrada;

if (typeof extraido === 'string') {
  extraido = JSON.parse(extraido);
}

if (
  extraido.output &&
  typeof extraido.output === 'object'
) {
  extraido = extraido.output;
}

const candidatoInicial =
  $('Buscar candidato PDF').first().json;

const candidatoAtual =
  $('Recarregar CEP antes da análise').first().json;

const candidato = {
  ...candidatoInicial,

  cep:
    candidatoAtual.cep
    ?? candidatoInicial.cep
    ?? null
};
const dadosArquivo = $('Extrair telefone').first().json;
const dadosDocumento = $('Preparar PDF para armazenamento').first().json;
const vagaAtual = candidato.vaga_atual && typeof candidato.vaga_atual === 'object' ? candidato.vaga_atual : null;
const vagasAtivas = Array.isArray(candidato.vagas_ativas) ? candidato.vagas_ativas : [];
const vagaEstaAtiva = vagaAtual?.status === 'ATIVA';
const minimoMeses = vagaEstaAtiva ? Math.max(0, Number(vagaAtual.experiencia_minima_meses ?? 0)) : 0;
const aceitaSemExperiencia = vagaEstaAtiva && (vagaAtual.aceita_sem_experiencia === true || minimoMeses === 0);
const exigirCompatibilidade = vagaEstaAtiva && vagaAtual.exigir_experiencia_compativel !== false;
const MINIMO_DIAS = Math.max(0, Math.ceil(minimoMeses * 365 / 12));
const DIA = 86400000;

function texto(v) { const s = String(v ?? '').trim(); return s || null; }
function numeros(v) { const s = String(v ?? '').replace(/\D/g, ''); return s || null; }
function norm(v) {
  return String(v ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toUpperCase()
    .replace(/\bAUX\.?\b/g, 'AUXILIAR')
    .replace(/\bSERV\.?\b/g, 'SERVICO')
    .replace(/\bLIMP\.?\b/g, 'LIMPEZA')
    .replace(/\bHIG\.?\b/g, 'HIGIENIZACAO')
    .replace(/[^A-Z0-9]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
function normalizarData(v) {
  if (!v) return null;
  const s = String(v).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const m = s.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  return m ? `${m[3]}-${m[2]}-${m[1]}` : null;
}
function dataBR(v) {
  const m = String(v ?? '').trim().match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (!m) return null;
  const d = new Date(Date.UTC(Number(m[3]), Number(m[2]) - 1, Number(m[1])));
  return Number.isNaN(d.getTime()) ? null : d;
}
function hojeUTC() { const a = new Date(); return new Date(Date.UTC(a.getUTCFullYear(), a.getUTCMonth(), a.getUTCDate())); }
function periodo(v) {
  const m = String(v ?? '').trim().match(/(\d{2}\/\d{2}\/\d{4})\s*-\s*(?:(\d{2}\/\d{2}\/\d{4})|(ATUAL|PRESENTE|EM ABERTO))/i);
  if (!m) return null;
  const inicio = dataBR(m[1]);
  let fim = m[2] ? dataBR(m[2]) : hojeUTC();
  if (!inicio || !fim) return null;
  const hoje = hojeUTC();
  if (fim > hoje) fim = hoje;
  if (fim < inicio) return null;
  return { inicio, fim, dias: Math.floor((fim - inicio) / DIA) + 1 };
}
function tempo(dias) {
  dias = Math.max(0, Number(dias || 0));
  const meses = Math.floor(dias / 30);
  const resto = dias % 30;
  const partes = [];
  if (meses) partes.push(`${meses} ${meses === 1 ? 'mês' : 'meses'}`);
  if (resto || !partes.length) partes.push(`${resto} ${resto === 1 ? 'dia' : 'dias'}`);
  return partes.join(' e ');
}
function lista(v) {
  return String(v ?? '').split(/[\n,;|]+/).map(x => norm(x)).filter(Boolean);
}
function cboNormalizado(v) { return String(v ?? '').replace(/\D/g, ''); }
function cboCombina(cbo, regra) {
  const atual = cboNormalizado(cbo);
  const r = cboNormalizado(regra);
  if (!atual || !r) return false;
  return r.length <= 4 ? atual.startsWith(r) : atual === r;
}

const IGNORADAS = new Set(['AUXILIAR','AJUDANTE','ASSISTENTE','OFICIAL','OPERADOR','OPERADORA','SERVICO','SERVICOS','GERAL','GERAIS','DE','DA','DO','DAS','DOS','EM','PARA','COM','I','II','III']);
let cargosCompativeis = lista(vagaAtual?.cargos_compativeis);
const cbosCompativeis = lista(vagaAtual?.cbos_compativeis);
if (!cargosCompativeis.length && vagaAtual) {
  const base = norm(`${vagaAtual.titulo ?? ''} ${vagaAtual.cargo ?? ''}`)
    .split(/[^A-Z0-9]+/)
    .filter(t => t.length >= 4 && !IGNORADAS.has(t));
  cargosCompativeis = [...new Set(base)];
}

function cargoCombina(cargo) {
  if (!exigirCompatibilidade) return true;
  const c = norm(cargo);
  if (!c) return false;

  const tokensCargo = new Set(
    c.split(' ').filter(token => token.length >= 3 && !IGNORADAS.has(token))
  );

  return cargosCompativeis.some((regraOriginal) => {
    const regra = norm(regraOriginal);
    if (!regra) return false;
    if (c.includes(regra) || regra.includes(c)) return true;

    const tokensRegra = regra
      .split(' ')
      .filter(token => token.length >= 3 && !IGNORADAS.has(token));
    if (!tokensRegra.length) return false;

    const emComum = tokensRegra.filter(token => tokensCargo.has(token));
    // Exige todos os termos relevantes da regra, ou pelo menos dois termos.
    return emComum.length === tokensRegra.length
      || (tokensRegra.length >= 2 && emComum.length >= 2);
  });
}
function experienciaCompativel(cargo, cbo) {
  if (!exigirCompatibilidade) return true;
  const porCbo = cbosCompativeis.some(regra => cboCombina(cbo, regra));
  const porCargo = cargoCombina(cargo);
  return porCbo || porCargo;
}
function formatarVagas(vagas) {
  if (!vagas.length) return 'No momento não há vagas ativas cadastradas.';
  return 'Escolha uma das vagas abaixo:\n\n' + vagas.map((v, i) => {
    const local = [v.bairro, v.cidade, v.estado].filter(Boolean).join(' - ');
    return `${i + 1}. ${v.titulo || v.cargo || 'Vaga'}${local ? ` — ${local}` : ''}`;
  }).join('\n') + '\n\nResponda com o número ou o nome da vaga.';
}

const brutas = Array.isArray(extraido.experiencias) ? extraido.experiencias : [];
const unicas = new Map();
for (const e of brutas) {
  const cargo = texto(e.cargo);
  const empregador = texto(e.empregador);
  const cbo = texto(e.cbo);
  const periodoOriginal = texto(e.periodo);
  const p = periodo(periodoOriginal);
  if (!periodoOriginal || !p) continue;
  const chave = norm(`${empregador}|${cargo}|${periodoOriginal}`);
  if (!unicas.has(chave)) {
    const compativel = experienciaCompativel(cargo, cbo);
    unicas.set(chave, {
      empregador, cargo, cbo, periodo: periodoOriginal,
      inicio: p.inicio.toISOString().slice(0,10),
      fim: p.fim.toISOString().slice(0,10),
      dias: p.dias,
      tempo: tempo(p.dias),
      compativel,
      atingiu_minimo: compativel && p.dias >= MINIMO_DIAS
    });
  }
}

const experienciasValidas = [...unicas.values()].sort((a,b) => b.inicio.localeCompare(a.inicio));
const compativeis = experienciasValidas.filter(e => e.compativel).sort((a,b) => b.dias - a.dias);
const maiorCompativel = compativeis[0] ?? null;
const experienciaAprovadora = aceitaSemExperiencia ? null : (compativeis.find(e => e.dias >= MINIMO_DIAS) ?? null);
const mediaDias = experienciasValidas.length
  ? Math.round(experienciasValidas.reduce((s,e) => s + e.dias, 0) / experienciasValidas.length)
  : 0;
const ordenadosDias = experienciasValidas.map(e => e.dias).sort((a,b) => a-b);
const medianaDias = ordenadosDias.length
  ? (ordenadosDias.length % 2 ? ordenadosDias[(ordenadosDias.length-1)/2] : Math.round((ordenadosDias[ordenadosDias.length/2-1] + ordenadosDias[ordenadosDias.length/2])/2))
  : 0;

let aprovado = null;
if (vagaEstaAtiva) {
  if (aceitaSemExperiencia) aprovado = true;
  else if (experienciasValidas.length) aprovado = experienciaAprovadora !== null;
}

const maiorDias = maiorCompativel?.dias ?? 0;
const faltamDias = aprovado === false ? Math.max(0, MINIMO_DIAS - maiorDias) : 0;
const faltamMeses = faltamDias ? Math.round((faltamDias / 30) * 10) / 10 : 0;
let motivoReprovacao = null;
if (aprovado === false) {
  motivoReprovacao = compativeis.length === 0
    ? `Nenhuma experiência compatível com a vaga foi identificada entre ${experienciasValidas.length} vínculo(s) válido(s).`
    : `A maior experiência compatível foi de ${tempo(maiorDias)}. O requisito é ${tempo(MINIMO_DIAS)}; faltaram ${tempo(faltamDias)}.`;
}

const criterio = !vagaEstaAtiva
  ? 'Vaga não selecionada ou inativa.'
  : aceitaSemExperiencia
    ? 'A vaga aceita candidatos sem experiência mínima.'
    : `Uma única experiência compatível por cargo ou CBO com pelo menos ${tempo(MINIMO_DIAS)}.`;

const observacaoTriagem = aprovado === true
  ? (aceitaSemExperiencia
      ? 'Aprovado: a vaga aceita candidato sem experiência mínima.'
      : `Aprovado pela experiência ${experienciaAprovadora.cargo || 'compatível'} (${experienciaAprovadora.cbo || 'CBO não informado'}), com ${experienciaAprovadora.tempo}.`)
  : aprovado === false
    ? motivoReprovacao
    : 'Análise inconclusiva: não foi possível validar períodos suficientes na CTPS.';

const cep = String(candidato.cep ?? '').replace(/\D/g, '');
const possuiCep = cep.length === 8;
const nome = texto(extraido.nome);
const primeiroNome = nome ? nome.split(/\s+/)[0] : '';
const saudacao = primeiroNome ? `Olá, ${primeiroNome}!` : 'Olá!';

let resultado, status, etapa, evento, proximaAcao, aguardando, mensagem, descricaoEvento;
if (!vagaAtual) {
  resultado='VAGA_NAO_SELECIONADA'; status='EM_PROCESSO'; etapa='ESCOLHENDO_VAGA'; evento='CTPS_RECEBIDA_SEM_VAGA'; proximaAcao='ESCOLHER_VAGA'; aguardando='VAGA';
  mensagem=`${saudacao} Recebi sua CTPS. Antes de concluir a análise, preciso saber para qual vaga você deseja se candidatar.\n\n${formatarVagas(vagasAtivas)}`;
