    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}
function bool(valor) {
  if (valor === true || valor === 1) return true;
  return ['true', 'sim', '1'].includes(normalizar(String(valor ?? '').replace(/^=+/, '')));
}
function opcao(valor) {
  const n = Number(String(valor ?? '').replace(/^=+/, '').trim());
  return [1, 2, 3].includes(n) ? n : null;
}
function pedeOutros(mensagem) {
