const retorno = $input.first().json ?? {};
const persistido = $('Persistir resposta IA').first().json ?? {};
let mensagem = String(retorno.mensagem_whatsapp ?? retorno.mensagem ?? '').trim();

if (/^(AGENDAR_ENTREVISTA|GERAR_OPCOES_ENTREVISTA|REAGENDAR_ENTREVISTA)$/i.test(mensagem)) {
