const entrada = $input.first().json;
const contexto = $('Contexto IA').first().json ?? {};
const candidato = contexto.candidato ?? {};
const documentos = Array.isArray(contexto.documentos) ? contexto.documentos : [];
const opcoesEntrevista = Array.isArray(contexto.opcoes_entrevista) ? contexto.opcoes_entrevista : [];
const entrevistaAtual = contexto.entrevista_atual && typeof contexto.entrevista_atual === 'object'
  ? contexto.entrevista_atual
  : null;
const mensagemAtual = String(contexto.mensagem_atual ?? '').trim();

function converterResposta(valor) {
  let atual = valor;
  for (let tentativa = 0; tentativa < 4; tentativa++) {
    if (atual && typeof atual === 'object' && !Array.isArray(atual)) {
      if (atual.mensagem !== undefined || atual.nova_etapa !== undefined || atual.novo_status !== undefined) {
        return atual;
      }
      if (atual.output !== undefined) { atual = atual.output; continue; }
      if (atual.response !== undefined) { atual = atual.response; continue; }
      if (atual.text !== undefined) { atual = atual.text; continue; }
      return atual;
    }
    break;
  }

  if (typeof atual !== 'string') {
    throw new Error(`A IA retornou um tipo inesperado: ${typeof atual}`);
  }

  let bruto = atual.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  const inicio = bruto.indexOf('{');
  const fim = bruto.lastIndexOf('}');
  if (inicio < 0 || fim <= inicio) {
    throw new Error(`Não foi possível localizar JSON na resposta: ${bruto.slice(0, 400)}`);
  }

  const convertido = JSON.parse(bruto.slice(inicio, fim + 1));
  return convertido.output && typeof convertido.output === 'object'
    ? convertido.output
    : convertido;
}

function texto(valor, padrao = '') {
  if (valor === null || valor === undefined) return padrao;
  return String(valor).trim().replace(/^=+(?=(true|false|null|\d))/i, '');
}

function normalizar(valor) {
  return String(valor ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

function booleanoOuNull(valor) {
  if (valor === true || valor === false) return valor;
  if (valor === 1) return true;
  if (valor === 0) return false;
  const v = normalizar(texto(valor));
  if (['true', 'sim', '1'].includes(v)) return true;
  if (['false', 'nao', '0'].includes(v)) return false;
  return null;
}

function booleano(valor) {
  const v = booleanoOuNull(valor);
  return v === true;
}

function numeroOpcao(valor) {
  const numero = Number(texto(valor));
  return [1, 2, 3].includes(numero) ? numero : null;
}

function normalizarTags(valor) {
  if (Array.isArray(valor)) {
    return valor.map(tag => texto(tag)).filter(Boolean).slice(0, 5);
  }
  if (typeof valor === 'string' && valor.trim()) {
    try {
      const lista = JSON.parse(valor);
      if (Array.isArray(lista)) return lista.map(tag => texto(tag)).filter(Boolean).slice(0, 5);
    } catch {}
    return valor.split(/[,;|]/).map(tag => texto(tag)).filter(Boolean).slice(0, 5);
  }
  return [];
}

function horarioLocal(iso) {
  if (!iso) return null;
  const data = new Date(iso);
  if (Number.isNaN(data.getTime())) return null;
  return new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    hour: '2-digit',
    minute: '2-digit',
    hourCycle: 'h23'
  }).format(data);
}

function textoOpcao(opcao) {
  const data = new Date(opcao.inicio);
  if (Number.isNaN(data.getTime())) return `Opção ${opcao.opcao}`;
  return new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    weekday: 'long',
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    hourCycle: 'h23'
  }).format(data);
}

function mensagemComOpcoes() {
  if (!opcoesEntrevista.length) {
    return 'As opções anteriores não estão mais disponíveis. Vou consultar novos horários para você.';
  }
  return 'Estas são as opções disponíveis:\n\n' +
    opcoesEntrevista.map(o => `${o.opcao}. ${textoOpcao(o)}`).join('\n') +
    '\n\nResponda com 1, 2 ou 3, ou informe o horário desejado.';
}

function opcaoPelaMensagem(mensagem) {
  const n = normalizar(mensagem);
  let match = n.match(/\b(?:opcao|numero|quero|escolho)?\s*([123])\b/);
  if (match) return Number(match[1]);
  if (/\bprimeir[ao]\b/.test(n)) return 1;
  if (/\bsegund[ao]\b/.test(n)) return 2;
  if (/\bterceir[ao]\b/.test(n)) return 3;

  const horaMatch = n.match(/\b([01]?\d|2[0-3])\s*(?:h|:)\s*([0-5]\d)\b/);
  if (!horaMatch) return null;
  const alvo = `${String(Number(horaMatch[1])).padStart(2, '0')}:${horaMatch[2]}`;
  const correspondentes = opcoesEntrevista.filter(o => horarioLocal(o.inicio) === alvo);
  return correspondentes.length === 1 ? Number(correspondentes[0].opcao) : null;
}

function pedeOutrosHorarios(mensagem) {
  const n = normalizar(mensagem);
  return /(outro horario|outros horarios|outra opcao|outras opcoes|outro dia|tem outro|tem mais|nenhum desses|nenhuma dessas|nao consigo|nao posso|horarios diferentes|novas opcoes)/.test(n);
}

function naoEntendeu(mensagem) {
  const n = normalizar(mensagem);
  return /^\?+$/.test(n) || /(nao entendi|como assim|pode explicar|qual eu escolho|quais eram os horarios|repete os horarios)/.test(n);
}

function confirmacaoCurta(mensagem) {
  const n = normalizar(mensagem).replace(/[.!?😊👍✅🙏]+/g, '').trim();
  return /^(ok|okay|certo|combinado|beleza|entendi|perfeito|obrigado|obrigada|valeu|ta bom|esta bem|show)$/.test(n);
}

function pedeDetalhesEntrevista(mensagem) {
  const n = normalizar(mensagem);
  return /(qual.*horario|que horas|quando.*entrevista|manda.*link|envia.*link|pode repetir|dados.*entrevista|link.*meet)/.test(n);
}

function pedeReagendamento(mensagem) {
  const n = normalizar(mensagem);
  return /(reagendar|remarcar|trocar.*horario|mudar.*horario|mudar.*entrevista|outro dia|nao vou conseguir|nao consigo comparecer|preciso.*outro horario|alterar.*agendamento)/.test(n);
}

function detalhesEntrevista(entrevista) {
  if (!entrevista?.inicio) return 'Sua entrevista está agendada, mas não consegui carregar os dados completos agora.';
  const data = new Intl.DateTimeFormat('pt-BR', {
    timeZone: 'America/Sao_Paulo',
    weekday: 'long',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hourCycle: 'h23'
  }).format(new Date(entrevista.inicio));
  const link = String(entrevista.meet_link || entrevista.google_event_url || '').trim();
  return `Sua entrevista está marcada para ${data}.${link ? `\n\nLink do Google Meet:\n${link}` : ''}`;
}

function parecePedidoDocumento(mensagem, termo) {
  const n = normalizar(mensagem);
  return n.includes(termo) && /(envie|manda|mande|preciso|necessario|faltando|aguardando)/.test(n);
}

const resposta = converterResposta(entrada.output ?? entrada.response ?? entrada.text ?? entrada);

const etapasPermitidas = new Set([
  'PRIMEIRO_CONTATO', 'PERGUNTANDO_EXPERIENCIA', 'ESCOLHENDO_VAGA',
  'AGUARDANDO_CTPS_CEP', 'AGUARDANDO_CTPS', 'AGUARDANDO_CEP',
  'ANALISANDO_DOCUMENTOS', 'APROVADO_TRIAGEM', 'REPROVADO_PRE_TRIAGEM',
  'REPROVADO_TRIAGEM', 'AGUARDANDO_APRESENTACAO', 'GERANDO_OPCOES_ENTREVISTA',
  'ESCOLHENDO_HORARIO', 'AGUARDANDO_ENTREVISTA', 'ENTREVISTA_AGENDADA',
  'CONTRATADO', 'ENCERRADO'
]);
const statusPermitidos = new Set(['NOVO', 'EM_PROCESSO', 'APROVADO', 'REPROVADO', 'CONTRATADO', 'ENCERRADO']);

let novaEtapa = etapasPermitidas.has(texto(resposta.nova_etapa))
  ? texto(resposta.nova_etapa)
  : texto(candidato.etapa, 'PRIMEIRO_CONTATO');
let novoStatus = statusPermitidos.has(texto(resposta.novo_status))
  ? texto(resposta.novo_status)
  : texto(candidato.status, 'NOVO');
let mensagem = texto(resposta.mensagem);
let evento = texto(resposta.evento);
let solicitarOpcoes = booleano(resposta.solicitar_opcoes_entrevista);
let opcaoEscolhida = numeroOpcao(resposta.opcao_horario_escolhida);

const etapaAtual = texto(candidato.etapa);
const statusAtual = texto(candidato.status);
const emAgenda = ['GERANDO_OPCOES_ENTREVISTA', 'ESCOLHENDO_HORARIO', 'AGUARDANDO_ENTREVISTA'].includes(etapaAtual)
  || opcoesEntrevista.length > 0;

if (!entrevistaAtual && emAgenda) {
  const opcaoDeterministica = opcaoPelaMensagem(mensagemAtual);

  if (pedeOutrosHorarios(mensagemAtual)) {
    solicitarOpcoes = true;
    opcaoEscolhida = null;
    novaEtapa = 'GERANDO_OPCOES_ENTREVISTA';
    novoStatus = 'APROVADO';
    evento = 'NOVAS_OPCOES_ENTREVISTA_SOLICITADAS';
    mensagem = 'Claro! Vou consultar três novas opções disponíveis para você.';
  } else if (opcaoDeterministica !== null) {
    solicitarOpcoes = false;
    opcaoEscolhida = opcaoDeterministica;
    novaEtapa = 'ESCOLHENDO_HORARIO';
    novoStatus = 'APROVADO';
    evento = 'HORARIO_ENTREVISTA_ESCOLHIDO';
    mensagem = 'Vou confirmar esse horário para você.';
  } else if (naoEntendeu(mensagemAtual)) {
    solicitarOpcoes = false;
    opcaoEscolhida = null;
    novaEtapa = 'ESCOLHENDO_HORARIO';
    novoStatus = 'APROVADO';
    evento = '';
    mensagem = mensagemComOpcoes();
  }
}

if (entrevistaAtual) {
  opcaoEscolhida = null;
  novoStatus = 'APROVADO';

  if (pedeReagendamento(mensagemAtual)) {
    solicitarOpcoes = true;
    novaEtapa = 'GERANDO_OPCOES_ENTREVISTA';
    evento = 'REAGENDAMENTO_SOLICITADO';
    mensagem = 'Claro! Vou cancelar o horário atual e consultar três novas opções disponíveis para você.';
  } else {
    solicitarOpcoes = false;
    novaEtapa = 'ENTREVISTA_AGENDADA';

    if (confirmacaoCurta(mensagemAtual)) {
      evento = '';
      mensagem = 'Combinado! Até a entrevista. 😊';
    } else if (pedeDetalhesEntrevista(mensagemAtual)) {
      evento = '';
      mensagem = detalhesEntrevista(entrevistaAtual);
    }
  }
}

// Nunca deixa marcadores internos chegarem ao WhatsApp.
if (/^(AGENDAR_ENTREVISTA|GERAR_OPCOES_ENTREVISTA)$/i.test(mensagem)) {
  mensagem = opcaoEscolhida !== null
    ? 'Vou confirmar esse horário para você.'
    : solicitarOpcoes
      ? 'Vou consultar novas opções disponíveis para você.'
      : mensagemComOpcoes();
}

const temCtps = contexto.tem_ctps === true || documentos.some(d => normalizar(d.tipo) === 'ctps');
const temCep = contexto.tem_cep === true || /^\d{8}$/.test(String(candidato.cep ?? '').replace(/\D/g, ''));
const etapasDocumentais = new Set(['AGUARDANDO_CTPS_CEP', 'AGUARDANDO_CTPS', 'AGUARDANDO_CEP']);
const etapasAprovadas = new Set(['APROVADO_TRIAGEM', 'AGUARDANDO_APRESENTACAO', 'GERANDO_OPCOES_ENTREVISTA', 'ESCOLHENDO_HORARIO', 'AGUARDANDO_ENTREVISTA', 'ENTREVISTA_AGENDADA']);

// Impede retrocesso depois de aprovação ou reprovação.
if (statusAtual === 'REPROVADO') {
  novoStatus = 'REPROVADO';
  novaEtapa = etapaAtual || 'REPROVADO_TRIAGEM';
  solicitarOpcoes = false;
  opcaoEscolhida = null;
}
if (statusAtual === 'APROVADO' && etapasAprovadas.has(etapaAtual) && etapasDocumentais.has(novaEtapa)) {
  novaEtapa = etapaAtual;
  novoStatus = 'APROVADO';
}

// Corrige pedidos duplicados de CTPS/CEP.
// A proteção considera tanto a etapa retornada quanto o próprio texto, pois o
// modelo pode preservar uma etapa avançada e ainda assim repetir o pedido.
const mensagemPedeCtps = parecePedidoDocumento(mensagem, 'ctps')
  || parecePedidoDocumento(mensagem, 'carteira de trabalho');
const mensagemPedeCep = parecePedidoDocumento(mensagem, 'cep');

if (
  temCtps
  && temCep
  && (
    etapasDocumentais.has(novaEtapa)
    || mensagemPedeCtps
    || mensagemPedeCep
  )
) {
  solicitarOpcoes = false;
  opcaoEscolhida = null;

  if (
    candidato.aprovado === true
    && !texto(candidato.apresentacao_profissional)
  ) {
    novaEtapa = 'AGUARDANDO_APRESENTACAO';
    novoStatus = 'APROVADO';
    evento = evento === 'APRESENTACAO_PROFISSIONAL_SOLICITADA'
      ? evento
      : '';
    mensagem = 'Recebi seu CEP e sua CTPS. Agora, antes da entrevista, conte brevemente sobre suas experiências e seus principais pontos fortes.';
  } else if (
    statusAtual === 'APROVADO'
    && texto(candidato.apresentacao_profissional)
    && !entrevistaAtual
  ) {
    novaEtapa = opcoesEntrevista.length
      ? 'ESCOLHENDO_HORARIO'
      : 'GERANDO_OPCOES_ENTREVISTA';
    novoStatus = 'APROVADO';
    solicitarOpcoes = opcoesEntrevista.length === 0;
    mensagem = opcoesEntrevista.length
      ? mensagemComOpcoes()
      : 'Recebi seu CEP e sua CTPS. Vou consultar opções disponíveis para a entrevista.';
  } else {
    novaEtapa = etapaAtual && !etapasDocumentais.has(etapaAtual)
      ? etapaAtual
      : 'ANALISANDO_DOCUMENTOS';
    novoStatus = statusAtual || novoStatus;
    mensagem = 'Recebi seu CEP e sua CTPS. A análise está em andamento e você não precisa enviar os documentos novamente.';
  }
}

if (temCtps && !temCep && (novaEtapa === 'AGUARDANDO_CTPS' || novaEtapa === 'AGUARDANDO_CTPS_CEP' || parecePedidoDocumento(mensagem, 'ctps'))) {
  novaEtapa = candidato.aprovado === true ? 'AGUARDANDO_CEP' : 'AGUARDANDO_CEP';
  mensagem = 'Sua CTPS já foi recebida. Agora preciso apenas do seu CEP com 8 números.';
}

if (temCep && !temCtps && (novaEtapa === 'AGUARDANDO_CEP' || novaEtapa === 'AGUARDANDO_CTPS_CEP' || parecePedidoDocumento(mensagem, 'cep'))) {
  novaEtapa = 'AGUARDANDO_CTPS';
  mensagem = 'Seu CEP já foi recebido. Agora preciso apenas da Carteira de Trabalho Digital em PDF.';
}

if (!mensagem) {
  mensagem = 'Certo. Vou continuar o atendimento a partir da etapa atual.';
}

const candidatoId = Number(candidato.id ?? entrada.candidato_id ?? entrada.id);
if (!Number.isInteger(candidatoId) || candidatoId <= 0) {
  throw new Error(`candidato_id inválido: ${candidato.id ?? entrada.candidato_id ?? entrada.id}`);
}

return [{
  json: {
    candidato_id: candidatoId,
    telefone: texto(candidato.telefone ?? $('Extrair telefone').first().json.telefone),
    mensagem,
    nome_informado: texto(resposta.nome_informado),
    nova_etapa: novaEtapa,
    novo_status: novoStatus,
    evento,
    experiencia_6_meses: booleanoOuNull(resposta.experiencia_6_meses),
    vaga_escolhida: texto(resposta.vaga_escolhida),
    apresentacao_profissional: texto(resposta.apresentacao_profissional),
    personalidade_resumo: texto(resposta.personalidade_resumo),
    personalidade_tags: normalizarTags(resposta.personalidade_tags),
    solicitar_opcoes_entrevista: solicitarOpcoes,
    opcao_horario_escolhida: opcaoEscolhida
  }
}];

const entrada = $input.first().json ?? {};
const paginas = Array.isArray(entrada.pages) ? entrada.pages : [];
const textoOcr = paginas
  .map((pagina, indice) => `### Página ${indice + 1}\n${String(pagina.markdown ?? pagina.text ?? '')}`)
  .join('\n\n')
  .trim();

const nomeArquivo = String(
  $('Extrair telefone').first().json.nome_arquivo
  ?? $('Preparar PDF para armazenamento').first().json.nome_arquivo_documento
  ?? ''
);

function normalizar(valor) {
  return String(valor ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

const conteudo = normalizar(`${nomeArquivo}\n${textoOcr}`);
const contar = (termos) => termos.reduce((total, termo) => total + (conteudo.includes(termo) ? 1 : 0), 0);

const sinaisCtpsFortes = [
  'carteira de trabalho digital',
  'contratos de trabalho',
  'dados pessoais',
  'registro de trabalho',
  'historico profissional',
  'remuneracoes',
  'vinculos empregaticios'
];
const sinaisCtpsComuns = [
  'data de admissao',
  'data admissao',
  'empregador',
  'cnpj',
  'cbo',
  'salario contratual',
  'tipo de contrato',
  'ocupacao inicial',
  'anotacoes'
];
const sinaisCurriculoFortes = [
  'curriculo',
  'curriculum vitae',
  'objetivo profissional',
  'resumo profissional',
  'experiencia profissional',
  'formacao academica'
];
const sinaisCurriculoComuns = [
  'habilidades',
  'competencias',
  'cursos complementares',
  'qualificacoes',
  'contato',
  'email',
  'telefone',
  'linkedin'
];

let pontosCtps = contar(sinaisCtpsFortes) * 3 + contar(sinaisCtpsComuns);
let pontosCurriculo = contar(sinaisCurriculoFortes) * 3 + contar(sinaisCurriculoComuns);

if (/ctps|carteira.*trabalho/i.test(nomeArquivo)) pontosCtps += 5;
if (/curr[ií]culo|curriculum|cv([._ -]|$)/i.test(nomeArquivo)) pontosCurriculo += 5;

let tipoDocumento = 'OUTRO';
let confianca = 'BAIXA';

if (pontosCtps >= 6 && pontosCtps >= pontosCurriculo + 2) {
  tipoDocumento = 'CTPS';
  confianca = pontosCtps >= 12 ? 'ALTA' : 'MEDIA';
} else if (pontosCurriculo >= 6 && pontosCurriculo >= pontosCtps + 2) {
  tipoDocumento = 'CURRICULO';
  confianca = pontosCurriculo >= 12 ? 'ALTA' : 'MEDIA';
}

return [{
  json: {
    ...entrada,
    tipo_documento: tipoDocumento,
    classificacao_confianca: confianca,
    pontos_ctps: pontosCtps,
    pontos_curriculo: pontosCurriculo,
    texto_ocr: textoOcr,
    classificacao: {
      tipo: tipoDocumento,
      confianca,
      pontos_ctps: pontosCtps,
      pontos_curriculo: pontosCurriculo,
      nome_arquivo: nomeArquivo
    }
  }
}];
